var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그들이야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼らだからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that these employees whom you'd been giving a lot of thought were absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他們是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그들과 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼らとともにいることを。","ENG":"that you'll be with them, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他們一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called them to your office. They said they'd be here soon.","TWN":"做好心理準備後，你將他們傳喚到老闆辦公室，他們說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"부르셨습니까, 마스터.","JPN":"お呼びですか、マスター。","ENG":"Did you call us, Master?","TWN":"主人找我嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"부르셨습니까, 마스터.","JPN":"お呼びですか、マスター。","ENG":"Did you call us, Master?","TWN":"主人找我嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"오늘은 중요한 날이라고 들었습니다.","JPN":"今日は大事な日だとお聞きしました。","ENG":"We've heard today is an important day.","TWN":"聽說今天是重要的日子。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"종신 계약이라고 하셨나요? 마스터와 정식으로 맺어지는 날.","JPN":"終身契約でしたか？　マスターと正式に結ばれる日。","ENG":"A lifetime contract, was it? The day we are formally bound to you, Master.","TWN":"是與主人正式簽訂終身契約的日子嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"하지만 이상하군요.","JPN":"ですが、おかしいですね。","ENG":"But it is strange.","TWN":"但我不太明白。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"저희는 마스터의 그림자 속에서 피는 검은 장미.","JPN":"私たちはマスターの影から咲く黒いバラ。","ENG":"We are the black rose, blooming in your shadow.","TWN":"我們使在主人的影子之中綻放的黑色玫瑰。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"이런 계약이 따로 없어도, 이미 마스터께 영원한 헌신을 맹세한 몸…….","JPN":"このような契約がなくとも、すでにマスターに永遠なる献身を誓ったはず……","ENG":"Even without such a contract, we have already pledged eternal loyalty to you...","TWN":"就算沒有簽訂契約，我們也已經對主人發誓要永遠效忠…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"따라서 이런 소모적인 행위에 어떤 의미가 있는지 모르겠군요.","JPN":"よって、このような非効率的な行為に何の意味があるのかわかりませんね。","ENG":"What, then, is the purpose of such a redundant act?","TWN":"因此，實在不明白為何要多此一舉呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"가르쳐 주시겠습니까, 마스터?","JPN":"教えていただけますか？　マスター。","ENG":"Would you care to enlighten us, Master?","TWN":"主人能否告訴我？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"그렇군요.","JPN":"そうですか。","ENG":"Right.","TWN":"原來如此。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"이해했습니다.","JPN":"理解しました。","ENG":"Understood.","TWN":"謝謝主人的說明。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"형식과 절차라는 것은 상당히 중요한 문제로군요.","JPN":"形式と段取りというものは相当重要な問題なのですね。","ENG":"So, formality and procedure carry significant weight.","TWN":"正式的文件與手續確實是非常重要呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"계약서에 함께 서명하는 것만으로도 동질감을 공유할 수 있다는 말씀이로군요.","JPN":"契約書に一緒に署名するだけでも、仲間意識を共有できるということですか。","ENG":"Simply signing a contract together allows one to feel a sense of unity... is that what you're saying?","TWN":"您的意思是，只要一起在契約書上簽名，也能產生情感連結對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"사실은 동질감이라는 게 무엇인지는 잘 모르겠습니다만.","JPN":"本当は仲間意識とは何なのかよくわかりませんが。","ENG":"Though we must admit, we don't quite understand what unity truly means.","TWN":"雖然我還搞不太清楚情感連結是什麼意思…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"마스터와 같은 곳에서, 같은 행위를 한다는 것은 썩 나쁘지 않은 느낌입니다.","JPN":"マスターと同じ場所で、同じ行為をするということはなかなか悪くない気分です。","ENG":"But to be in the same place, doing the same thing as you, Master... it's not such a bad feeling.","TWN":"但能夠與主人在同一個地方，做同樣的事，倒也不是什麼壞事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"그렇군요. 이것이 동질감… 이것이 종신 계약……!","JPN":"そうですね。これが仲間意識……これが終身契約……！","ENG":"So this is what a sense of unity feels like... this is what a lifetime contract means...!","TWN":"原來如此，這就是情感連結…這就是終身契約…！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"저희가 이해한 사항이 맞을까요?","JPN":"私たちの理解で合ってるのでしょうか？","ENG":"Have we understood correctly?","TWN":"我們理解的方向正確嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"저희가 옳게 이해했다면…….","JPN":"私たちが正しく理解したのなら……","ENG":"If we have...","TWN":"若我們理解得正確……."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"마스터. 부디 칭찬을.","JPN":"マスター、どうかお褒めの言葉を。","ENG":"Requesting praise, Master.","TWN":"主人，請誇我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"ROSE_BETA_MAID_NULL","text":{"KOREA":"칭찬을.","JPN":"お褒めの言葉を。","ENG":"Requesting praise.","TWN":"請誇我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};